import React, { useState, useEffect } from "react";
import axios from "axios";

const API = "http://localhost:5000";

const css = `
@import url('https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap');
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
:root{
  --navy:#0f172a;--navy2:#1e293b;--navy3:#334155;
  --orange:#f97316;--orange2:#ea580c;
  --blue:#3b82f6;--green:#22c55e;--red:#ef4444;--yellow:#eab308;
  --text:#f8fafc;--text2:#94a3b8;--text3:#475569;
  --card:#1e293b;--border:#2d3f55;
}
body{font-family:'Outfit',sans-serif;background:var(--navy);color:var(--text);min-height:100vh}
button,input,select{font-family:'Outfit',sans-serif;cursor:pointer}
/* NAV */
.nav{background:var(--navy2);border-bottom:1px solid var(--border);position:sticky;top:0;z-index:200}
.nav-inner{max-width:1400px;margin:0 auto;display:flex;align-items:center;gap:0.5rem;padding:0 1.5rem;height:64px}
.nav-logo{font-size:1.35rem;font-weight:800;color:var(--orange);letter-spacing:-1px;white-space:nowrap;margin-right:1rem;display:flex;align-items:center;gap:0.4rem}
.nav-spacer{flex:1}
.nav-btn{background:none;border:none;color:var(--text2);padding:0.5rem 0.8rem;border-radius:8px;font-size:0.85rem;font-weight:500;display:flex;align-items:center;gap:0.4rem;transition:all 0.2s;white-space:nowrap}
.nav-btn:hover{color:var(--text);background:var(--navy3)}
.nav-btn.active{color:var(--orange);background:rgba(249,115,22,0.12)}
.nav-out{color:var(--red)!important}
.nav-out:hover{background:rgba(239,68,68,0.1)!important}
/* MAIN */
.main{max-width:1400px;margin:0 auto;padding:2rem 1.5rem}
/* PAGE HEADER */
.ph{margin-bottom:2rem}
.ph h1{font-size:1.75rem;font-weight:700;letter-spacing:-0.5px}
.ph p{color:var(--text2);margin-top:0.25rem;font-size:0.9rem}
/* CARD */
.card{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:1.75rem}
/* STATS */
.stats-row{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem;margin-bottom:2rem}
.stat{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:1.5rem;display:flex;align-items:center;gap:1rem;transition:transform 0.2s,border-color 0.2s}
.stat:hover{transform:translateY(-2px);border-color:var(--orange)}
.stat-ico{width:50px;height:50px;border-radius:12px;display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:1.4rem}
.stat-val{font-size:1.6rem;font-weight:800;font-family:'JetBrains Mono',monospace}
.stat-lbl{color:var(--text2);font-size:0.8rem;margin-top:0.1rem}
/* ACTIONS */
.actions-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:1rem}
.at{background:var(--card);border:1px solid var(--border);border-radius:16px;padding:1.5rem;cursor:pointer;transition:all 0.2s}
.at:hover{transform:translateY(-3px);box-shadow:0 8px 32px rgba(0,0,0,0.4)}
.at-ico{width:44px;height:44px;border-radius:10px;display:flex;align-items:center;justify-content:center;margin-bottom:1rem;font-size:1.3rem}
.at h3{font-size:1rem;font-weight:600;margin-bottom:0.2rem}
.at p{color:var(--text2);font-size:0.82rem;line-height:1.4}
/* TABLE */
.tbl-wrap{background:var(--card);border:1px solid var(--border);border-radius:16px;overflow:hidden}
.tbl-top{padding:1.2rem 1.5rem;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--border)}
.tbl-top h2{font-size:1rem;font-weight:600;display:flex;align-items:center;gap:0.5rem}
.tbl-count{background:rgba(249,115,22,0.15);color:var(--orange);font-size:0.73rem;font-weight:700;padding:0.2rem 0.6rem;border-radius:20px}
table{width:100%;border-collapse:collapse}
th{padding:0.85rem 1.25rem;text-align:left;font-size:0.73rem;font-weight:700;text-transform:uppercase;letter-spacing:0.8px;color:var(--text2);background:rgba(255,255,255,0.03);border-bottom:1px solid var(--border)}
td{padding:1rem 1.25rem;border-bottom:1px solid rgba(255,255,255,0.04);font-size:0.9rem}
tbody tr{transition:background 0.15s}
tbody tr:hover{background:rgba(255,255,255,0.03)}
tbody tr:last-child td{border-bottom:none}
.tid{color:var(--text2);font-family:'JetBrains Mono',monospace;font-size:0.8rem}
.tname{font-weight:600}
.tprice{font-family:'JetBrains Mono',monospace;color:var(--orange)}
/* BADGES */
.badge{display:inline-flex;align-items:center;gap:0.3rem;padding:0.28rem 0.7rem;border-radius:20px;font-size:0.76rem;font-weight:600}
.badge::before{content:'';width:5px;height:5px;border-radius:50%;background:currentColor}
.bg{background:rgba(34,197,94,0.12);color:var(--green)}
.by{background:rgba(234,179,8,0.12);color:var(--yellow)}
.br{background:rgba(239,68,68,0.12);color:var(--red)}
/* FORM */
.fw{max-width:500px}
.fg{margin-bottom:1.2rem}
.fg label{display:block;font-size:0.78rem;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;color:var(--text2);margin-bottom:0.45rem}
.fg input{width:100%;background:var(--navy);border:1px solid var(--border);border-radius:10px;padding:0.85rem 1rem;color:var(--text);font-size:0.95rem;outline:none;transition:border-color 0.2s,box-shadow 0.2s}
.fg input:focus{border-color:var(--orange);box-shadow:0 0 0 3px rgba(249,115,22,0.15)}
.fg input::placeholder{color:var(--text3)}
/* BUTTONS */
.btn{display:inline-flex;align-items:center;justify-content:center;gap:0.5rem;padding:0.85rem 1.5rem;border-radius:10px;border:none;font-size:0.92rem;font-weight:600;transition:all 0.2s;width:100%}
.bo{background:var(--orange);color:#fff}.bo:hover{background:var(--orange2);transform:translateY(-1px);box-shadow:0 4px 16px rgba(249,115,22,0.35)}
.bg2{background:var(--green);color:#0a0a0a}.bg2:hover{background:#16a34a;transform:translateY(-1px)}
.bb{background:var(--blue);color:#fff}.bb:hover{background:#2563eb;transform:translateY(-1px)}
.bred{background:var(--red);color:#fff}.bred:hover{background:#dc2626;transform:translateY(-1px)}
.bgh{background:var(--navy3);color:var(--text);border:1px solid var(--border)}.bgh:hover{background:var(--navy2)}
/* ALERTS */
.al{padding:0.9rem 1.1rem;border-radius:10px;margin-bottom:1.4rem;font-size:0.88rem;display:flex;align-items:center;gap:0.5rem}
.als{background:rgba(34,197,94,0.1);border:1px solid rgba(34,197,94,0.25);color:var(--green)}
.ale{background:rgba(239,68,68,0.1);border:1px solid rgba(239,68,68,0.25);color:var(--red)}
.alw{background:rgba(234,179,8,0.1);border:1px solid rgba(234,179,8,0.25);color:var(--yellow)}
/* LOGIN */
.lw{min-height:100vh;display:flex;align-items:center;justify-content:center;background:var(--navy);position:relative;overflow:hidden}
.lb1{position:absolute;width:600px;height:600px;border-radius:50%;background:radial-gradient(circle,rgba(249,115,22,0.08) 0%,transparent 70%);top:-200px;right:-100px;pointer-events:none}
.lb2{position:absolute;width:400px;height:400px;border-radius:50%;background:radial-gradient(circle,rgba(59,130,246,0.06) 0%,transparent 70%);bottom:-100px;left:-100px;pointer-events:none}
.lbox{background:var(--card);border:1px solid var(--border);border-radius:24px;padding:3rem;width:440px;position:relative;z-index:1;animation:fu 0.4s ease}
.llogo{font-size:2rem;font-weight:800;color:var(--orange);letter-spacing:-1px;margin-bottom:0.4rem;display:flex;align-items:center;gap:0.5rem}
.lsub{color:var(--text2);margin-bottom:2rem;font-size:0.9rem}
.lhint{margin-top:1.4rem;padding:0.8rem;background:rgba(59,130,246,0.08);border:1px solid rgba(59,130,246,0.2);border-radius:8px;font-size:0.8rem;color:var(--text2);text-align:center}
.lhint strong{color:var(--blue)}
/* SEARCH */
.phead{display:flex;align-items:center;justify-content:space-between;margin-bottom:1.5rem;flex-wrap:wrap;gap:1rem}
.sbar{display:flex;align-items:center;gap:0.5rem;background:var(--card);border:1px solid var(--border);border-radius:10px;padding:0.6rem 1rem;min-width:250px}
.sbar input{background:none;border:none;outline:none;color:var(--text);font-size:0.88rem;flex:1}
.sbar input::placeholder{color:var(--text2)}
/* EMPTY */
.empty{padding:3.5rem 2rem;text-align:center;color:var(--text2)}
.empty p{font-size:0.9rem;margin-top:0.75rem}
/* TOAST */
.toast{position:fixed;bottom:2rem;right:2rem;z-index:9999;padding:1rem 1.5rem;border-radius:12px;display:flex;align-items:center;gap:0.75rem;box-shadow:0 8px 32px rgba(0,0,0,0.5);animation:fu 0.3s ease;max-width:360px;font-size:0.88rem;font-weight:500;color:#fff}
/* ANIM */
@keyframes fu{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
.page{animation:fu 0.3s ease}
@media(max-width:900px){.stats-row,.actions-grid{grid-template-columns:repeat(2,1fr)}}
@media(max-width:600px){.stats-row,.actions-grid{grid-template-columns:1fr}.lbox{width:calc(100vw - 2rem);padding:2rem}}
`;

function StyleTag() {
  useEffect(() => {
    const el = document.createElement("style");
    el.innerHTML = css;
    document.head.appendChild(el);
    document.title = "InvenTrack";
    return () => document.head.removeChild(el);
  }, []);
  return null;
}

function Toast({ msg, type, onClose }) {
  useEffect(() => { if (!msg) return; const t = setTimeout(onClose, 3500); return () => clearTimeout(t); }, [msg]);
  if (!msg) return null;
  const bg = type === "success" ? "#14532d" : type === "warn" ? "#713f12" : "#7f1d1d";
  const border = type === "success" ? "#22c55e" : type === "warn" ? "#eab308" : "#ef4444";
  return <div className="toast" style={{ background: bg, border: `1px solid ${border}` }}>{msg}</div>;
}

function Navbar({ page, setPage, onLogout }) {
  const links = [
    { id: "dashboard", label: "Dashboard" },
    { id: "add",       label: "➕ Add" },
    { id: "view",      label: "📋 Products" },
    { id: "update",    label: "✏️ Update" },
    { id: "delete",    label: "🗑️ Delete" },
  ];
  return (
    <nav className="nav">
      <div className="nav-inner">
        <div className="nav-logo">📦 InvenTrack</div>
        {links.map(l => (
          <button key={l.id} className={`nav-btn${page === l.id ? " active" : ""}`} onClick={() => setPage(l.id)}>
            {l.label}
          </button>
        ))}
        <div className="nav-spacer" />
        <button className="nav-btn nav-out" onClick={onLogout}>⏻ Logout</button>
      </div>
    </nav>
  );
}

function Login({ onLogin }) {
  const [u, setU] = useState(""); const [p, setP] = useState(""); const [err, setErr] = useState("");
  const go = () => { if (u === "admin" && p === "admin123") onLogin(); else setErr("Invalid credentials."); };
  return (
    <div className="lw">
      <div className="lb1" /><div className="lb2" />
      <div className="lbox">
        <div className="llogo">📦 InvenTrack</div>
        <div className="lsub">Inventory Management System</div>
        {err && <div className="al ale">⚠ {err}</div>}
        <div className="fg"><label>Username</label>
          <input placeholder="Enter username" value={u} onChange={e => { setU(e.target.value); setErr(""); }} /></div>
        <div className="fg"><label>Password</label>
          <input type="password" placeholder="Enter password" value={p}
            onChange={e => { setP(e.target.value); setErr(""); }}
            onKeyDown={e => e.key === "Enter" && go()} /></div>
        <button className="btn bo" onClick={go}>Sign In →</button>
        <div className="lhint">Demo: <strong>admin</strong> / <strong>admin123</strong></div>
      </div>
    </div>
  );
}

function Dashboard({ setPage }) {
  const [s, setS] = useState({ total: "—", qty: "—", value: "—", low: "—" });
  useEffect(() => {
    axios.get(`${API}/products`).then(r => {
      const d = r.data;
      setS({
        total: d.length,
        qty: d.reduce((a, p) => a + +p.quantity, 0),
        value: "₹" + d.reduce((a, p) => a + +p.price * +p.quantity, 0).toLocaleString("en-IN"),
        low: d.filter(p => +p.quantity <= 5).length,
      });
    }).catch(() => {});
  }, []);
  const stats = [
    { val: s.total, lbl: "Total Products",    ico: "📦", bg: "rgba(249,115,22,0.12)", col: "#f97316" },
    { val: s.qty,   lbl: "Units in Stock",     ico: "🔢", bg: "rgba(59,130,246,0.12)", col: "#3b82f6" },
    { val: s.value, lbl: "Inventory Value",    ico: "💰", bg: "rgba(34,197,94,0.12)",  col: "#22c55e" },
    { val: s.low,   lbl: "Low Stock Alerts",   ico: "⚠️", bg: "rgba(239,68,68,0.12)",  col: "#ef4444" },
  ];
  const actions = [
    { id: "add",    ico: "➕", lbl: "Add Product",    desc: "Add new item to inventory",    bg: "rgba(34,197,94,0.1)",  col: "#22c55e" },
    { id: "view",   ico: "📋", lbl: "View Products",  desc: "Browse & search all products",  bg: "rgba(59,130,246,0.1)", col: "#3b82f6" },
    { id: "update", ico: "✏️", lbl: "Update Stock",   desc: "Edit product details & prices", bg: "rgba(249,115,22,0.1)", col: "#f97316" },
    { id: "delete", ico: "🗑️", lbl: "Delete Product", desc: "Remove items from inventory",   bg: "rgba(239,68,68,0.1)",  col: "#ef4444" },
  ];
  return (
    <div className="page">
      <div className="ph"><h1>Dashboard</h1><p>Welcome back, Admin · Inventory overview</p></div>
      <div className="stats-row">
        {stats.map((s, i) => (
          <div className="stat" key={i}>
            <div className="stat-ico" style={{ background: s.bg }}>{s.ico}</div>
            <div><div className="stat-val" style={{ color: s.col }}>{s.val}</div><div className="stat-lbl">{s.lbl}</div></div>
          </div>
        ))}
      </div>
      <div className="ph" style={{ marginBottom: "1rem" }}><h1 style={{ fontSize: "1.15rem" }}>Quick Actions</h1></div>
      <div className="actions-grid">
        {actions.map(a => (
          <div className="at" key={a.id} onClick={() => setPage(a.id)}>
            <div className="at-ico" style={{ background: a.bg }}>{a.ico}</div>
            <h3>{a.lbl}</h3><p>{a.desc}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

function AddProduct({ toast }) {
  const [f, setF] = useState({ name: "", quantity: "", price: "" });
  const [err, setErr] = useState("");
  const set = k => e => setF(p => ({ ...p, [k]: e.target.value }));
  const submit = () => {
    if (!f.name || !f.quantity || !f.price) { setErr("All fields are required."); return; }
    axios.post(`${API}/addproduct`, f)
      .then(() => { toast(`✓ "${f.name}" added!`, "success"); setF({ name: "", quantity: "", price: "" }); setErr(""); })
      .catch(() => toast("Failed — is the backend running?", "error"));
  };
  return (
    <div className="page">
      <div className="ph"><h1>Add Product</h1><p>Add a new item to your inventory</p></div>
      <div className="card fw">
        {err && <div className="al ale">⚠ {err}</div>}
        <div className="fg"><label>Product Name</label><input placeholder="e.g. Laptop Pro X1" value={f.name} onChange={set("name")} /></div>
        <div className="fg"><label>Quantity</label><input type="number" min="0" placeholder="e.g. 10" value={f.quantity} onChange={set("quantity")} /></div>
        <div className="fg"><label>Price (₹)</label><input type="number" min="0" placeholder="e.g. 50000" value={f.price} onChange={set("price")} /></div>
        <button className="btn bg2" onClick={submit}>➕ Add Product</button>
      </div>
    </div>
  );
}

function ViewProducts() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [err, setErr] = useState("");
  useEffect(() => {
    axios.get(`${API}/products`)
      .then(r => { setProducts(r.data); setLoading(false); })
      .catch(() => { setErr("Could not connect to backend."); setLoading(false); });
  }, []);
  const filtered = products.filter(p =>
    p.name.toLowerCase().includes(search.toLowerCase()) || String(p.id).includes(search)
  );
  const badge = q => {
    if (+q <= 0) return <span className="badge br">Out of Stock</span>;
    if (+q <= 5) return <span className="badge by">Low Stock</span>;
    return <span className="badge bg">In Stock</span>;
  };
  return (
    <div className="page">
      <div className="phead">
        <div className="ph" style={{ margin: 0 }}><h1>Products</h1><p>{filtered.length} of {products.length} items</p></div>
        <div className="sbar">🔍 <input placeholder="Search by name or ID…" value={search} onChange={e => setSearch(e.target.value)} /></div>
      </div>
      {err && <div className="al ale">⚠ {err}</div>}
      <div className="tbl-wrap">
        <div className="tbl-top">
          <h2>Inventory <span className="tbl-count">{filtered.length}</span></h2>
        </div>
        <table>
          <thead><tr><th>ID</th><th>Product Name</th><th>Quantity</th><th>Price (₹)</th><th>Total Value</th><th>Status</th></tr></thead>
          <tbody>
            {loading && <tr><td colSpan="6" style={{ padding: "3rem", textAlign: "center", color: "#94a3b8" }}>Loading…</td></tr>}
            {!loading && filtered.length === 0 && (
              <tr><td colSpan="6"><div className="empty">📦<p>{search ? "No products match your search." : "No products yet. Add some!"}</p></div></td></tr>
            )}
            {filtered.map(p => (
              <tr key={p.id}>
                <td className="tid">#{p.id}</td>
                <td className="tname">{p.name}</td>
                <td>{p.quantity}</td>
                <td className="tprice">₹{(+p.price).toLocaleString("en-IN")}</td>
                <td style={{ color: "#64748b", fontFamily: "'JetBrains Mono',monospace", fontSize: "0.82rem" }}>
                  ₹{(+p.price * +p.quantity).toLocaleString("en-IN")}
                </td>
                <td>{badge(p.quantity)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

function UpdateProduct({ toast }) {
  const [f, setF] = useState({ id: "", name: "", quantity: "", price: "" });
  const [err, setErr] = useState("");
  const set = k => e => setF(p => ({ ...p, [k]: e.target.value }));
  const submit = () => {
    if (!f.id || !f.name || !f.quantity || !f.price) { setErr("All fields are required."); return; }
    axios.put(`${API}/updateproduct/${f.id}`, { name: f.name, quantity: f.quantity, price: f.price })
      .then(() => { toast(`✓ Product #${f.id} updated!`, "success"); setF({ id: "", name: "", quantity: "", price: "" }); setErr(""); })
      .catch(() => toast("Update failed — check the product ID.", "error"));
  };
  return (
    <div className="page">
      <div className="ph"><h1>Update Product</h1><p>Edit an existing product's details</p></div>
      <div className="card fw">
        {err && <div className="al ale">⚠ {err}</div>}
        <div className="fg"><label>Product ID</label><input type="number" placeholder="e.g. 1" value={f.id} onChange={set("id")} /></div>
        <div className="fg"><label>New Name</label><input placeholder="e.g. Laptop Pro X2" value={f.name} onChange={set("name")} /></div>
        <div className="fg"><label>New Quantity</label><input type="number" min="0" placeholder="e.g. 15" value={f.quantity} onChange={set("quantity")} /></div>
        <div className="fg"><label>New Price (₹)</label><input type="number" min="0" placeholder="e.g. 55000" value={f.price} onChange={set("price")} /></div>
        <button className="btn bb" onClick={submit}>✏️ Update Product</button>
      </div>
    </div>
  );
}

function DeleteProduct({ toast }) {
  const [id, setId] = useState(""); const [confirm, setConfirm] = useState(false); const [err, setErr] = useState("");
  const tryDelete = () => {
    if (!id) { setErr("Enter a product ID."); return; }
    if (!confirm) { setConfirm(true); return; }
    axios.delete(`${API}/deleteproduct/${id}`)
      .then(() => { toast(`✓ Product #${id} deleted.`, "success"); setId(""); setConfirm(false); setErr(""); })
      .catch(() => toast("Delete failed — check the ID.", "error"));
  };
  return (
    <div className="page">
      <div className="ph"><h1>Delete Product</h1><p>Permanently remove a product from inventory</p></div>
      <div className="card fw">
        {err && <div className="al ale">⚠ {err}</div>}
        <div className="fg"><label>Product ID</label>
          <input type="number" placeholder="Enter ID to delete" value={id}
            onChange={e => { setId(e.target.value); setConfirm(false); setErr(""); }} /></div>
        {confirm && <div className="al alw">⚠️ Are you sure you want to delete product #{id}? This cannot be undone.</div>}
        <div style={{ display: "flex", gap: "0.75rem" }}>
          <button className="btn bred" onClick={tryDelete}>{confirm ? "⚠️ Confirm Delete" : "🗑️ Delete Product"}</button>
          {confirm && <button className="btn bgh" style={{ width: "auto", flex: 1 }} onClick={() => { setConfirm(false); setErr(""); }}>Cancel</button>}
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [loggedIn, setLoggedIn] = useState(false);
  const [page, setPage] = useState("dashboard");
  const [toastMsg, setToastMsg] = useState(""); const [toastType, setToastType] = useState("success");
  const toast = (msg, type = "success") => { setToastMsg(msg); setToastType(type); };

  if (!loggedIn) return (<><StyleTag /><Login onLogin={() => setLoggedIn(true)} /></>);
  return (
    <>
      <StyleTag />
      <Navbar page={page} setPage={setPage} onLogout={() => { setLoggedIn(false); setPage("dashboard"); }} />
      <div className="main">
        {page === "dashboard" && <Dashboard setPage={setPage} />}
        {page === "add"       && <AddProduct toast={toast} />}
        {page === "view"      && <ViewProducts />}
        {page === "update"    && <UpdateProduct toast={toast} />}
        {page === "delete"    && <DeleteProduct toast={toast} />}
      </div>
      <Toast msg={toastMsg} type={toastType} onClose={() => setToastMsg("")} />
    </>
  );
}
